migrate((app) => {
    // First, find the users collection to get its ID for the relation field
    const usersCollection = app.findCollectionByNameOrId("users");

    // Create the posts collection with an author relation field pointing to users
    const postsCollection = new Collection({
        type: "base",
        name: "posts",
        listRule: "",
        viewRule: "",
        createRule: "",
        updateRule: "",
        deleteRule: "",
        fields: [
            {
                type: "text",
                name: "title",
                required: true,
            },
            {
                type: "relation",
                name: "author",
                required: true,
                collectionId: usersCollection.id,
                cascadeDelete: false,
                maxSelect: 1,
            },
        ],
        indexes: [
            "CREATE INDEX idx_posts_author ON posts (author)",
        ],
    });

    app.save(postsCollection);

    // Create the user_post_counts view collection
    const userPostCountsView = new Collection({
        type: "view",
        name: "user_post_counts",
        listRule: "",
        viewRule: "",
        viewQuery: `SELECT
    users.id,
    users.username,
    COUNT(posts.id) AS post_count
FROM users
LEFT JOIN posts ON posts.author = users.id
GROUP BY users.id`,
    });

    app.save(userPostCountsView);
}, (app) => {
    // Down migration: delete both collections
    try {
        const view = app.findCollectionByNameOrId("user_post_counts");
        app.delete(view);
    } catch (e) {
        // silently ignore if already deleted
    }

    try {
        const posts = app.findCollectionByNameOrId("posts");
        app.delete(posts);
    } catch (e) {
        // silently ignore if already deleted
    }
});
